VALUES
  ('islands-e3452428-moex-00100', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政機關為協助下級機關或屬官統一解釋法令而訂定之規定，其訂定程序，下列敘述何者正確？ 應舉行聽證程序 應經上級機關核定 應由行政機關之首長簽署，並登載於政府公報發布之 於擬定之過程中，應將規定公告於政府公報或新聞紙，並載明任何人得於期間內向機關陳述意見之 意旨', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00101', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於法規命令訂定之敘述，下列何者錯誤？ 不得牴觸憲法及法律，亦不得牴觸上級機關訂定之法規命令 人民或團體享有得向主管機關提出訂定法規命令之請求權 法規命令必須詳列授權依據並不得逾越授權範圍 訂定法規命令之行政機關必須是法律授權指定之機關', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00102', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '領有身心障礙證明者報考公務人員身心障礙特考時，辦理考試機關對於其是否符合身心障礙資格不 得另為不同之認定，為行政處分之何種效力？ 構成要件效力  確定力  執行力  確認效力', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00103', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '依行政程序法規定，關於行政程序之重開，下列敘述何者正確？ 程序重開之申請人，僅限於行政處分相對人 程序重開之申請，原則上應自法定救濟期間後30日內為之 行政機關拒絕重開程序之決定，不是行政處分 發現行政處分作成後始存在之新證據，亦得申請程序重開', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00104', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '甲向A市政府申請餐廳營業許可獲准，公文內容為：「台端申請照准，但系爭餐廳之隔音設備未達 標準，應於30日內改善。」該許可之法律性質為何？ 附期限之行政處分    附負擔之行政處分 附條件之行政處分    附廢止權保留之行政處分', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00105', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者非屬行政處分無效之事由？ 不能由書面處分中得知處分機關  應以證書方式作成而未給予證書 缺乏事務權限    未記明理由', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00106', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '已取得建築許可之土地於施工後，發現在建築基地上存有先民遺跡，經文化資產保存主管機關指定 為考古遺址，作成建築許可之機關應如何處理？ 撤銷該建築許可 確認該建築許可為無效 廢止該建築許可 經指定為考古遺址後，該建築許可即失效，故無庸處理 3601', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00107', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政程序法上和解契約之敘述，下列何者錯誤？ 作成處分所依據之事實或法律關係經依職權調查仍不能確定者，得締結和解契約 為行政機關基於提升行政效能與組織重整而採取之行政行為 締約雙方應互相退讓以達成合意 行政機關為有效達成行政目的並解決紛爭而與相對人締結之約定', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00108', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者非屬行政契約？ 人民將郵件交由中華郵政公司遞送 教育部與公費生間之服務協議 衛生福利部中央健康保險署與特約醫事服務機構間之特約 公立大學與教師間之聘約', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00109', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者非屬行政事實行為？ 警察執行集會解散命令之驅離行為  警察對於現行犯使用警械 主管機關警告某種果乾可能殘留病毒  主管機關劃設禁止停車之標線', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL)
